BEGIN
  INSERT INTO orders (customer_name) VALUES (p_customer);
  INSERT INTO order_items (order_id, product_id, qty, unit_price) VALUES (LAST_INSERT_ID(), p_product_id, p_qty, (SELECT unit_price FROM products WHERE product_id = p_product_id));
END

BEGIN
  INSERT INTO audit_log (event_type) VALUES (p_event);
  RETURN 1;
END

BEGIN
  DECLARE v_sql VARCHAR(500);
  SET v_sql = 'SELECT * FROM audit_log WHERE audit_id = 1';
  PREPARE stmt FROM v_sql;
  EXECUTE stmt;
  DEALLOCATE PREPARE stmt;
END
